var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하아……","JPN":"はあ……","ENG":"*Sigh*","TWN":"呼……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"조금만 더 가면 제단에 도착할 수 있어.","JPN":"あと少しで祭壇に着く。","ENG":"I’ll reach the altar soon.","TWN":"就快到祭壇了。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"미나토님은 오지 못하는 걸까?","JPN":"湊様は来れないのかしら？","ENG":"I wonder if Mr. Nayuka is coming.","TWN":"南裕夏是來不了嗎？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"집에서 치나츠 널 억지로 결혼시키려 한다고?","JPN":"家の人が千夏を無理やり結婚させようとしてるの？","ENG":"They are marrying you off?","TWN":"家人要逼你結婚？"},"stage":{"bg":"NANAHARA_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"도망치고 싶으면 도망치고, 하기 싫으면 싫다고 말해버려.","JPN":"逃げたいなら逃げて、やりたくないなら嫌って言っちゃえ。","ENG":"Run away if you will, or just tell them that you don’t want to.","TWN":"想逃就逃，不願意就說不願意吧。"},"stage":{"bg":"NANAHARA_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"그게 평범한 거잖아?","JPN":"それが普通だろ？","ENG":"That’s an ordinary thing to do, isn’t it?","TWN":"這不是很正常的嗎？"},"stage":{"bg":"NANAHARA_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"그래도 정 방법이 없다고 느껴질 땐, 날 찾아와!","JPN":"それでも本当に方法がないと思った時は、僕のところに来て！","ENG":"If you still can’t find a way out, come and find me!","TWN":"真的覺得沒辦法的時候，就來找我吧！"},"stage":{"bg":"NANAHARA_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"곤경에 처한 사람을 돕는 건 당연한 일이니까.","JPN":"困っている人を助けるのは、当たり前のことだから。","ENG":"Helping someone in trouble is also an ordinary thing to do.","TWN":"因為幫助有困難的人是理所當然的。"},"stage":{"bg":"NANAHARA_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……그래.","JPN":"……そうね。","ENG":"... Yes.","TWN":"……好。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"어쩌면, 혼자 마무리 짓는 편이 나은 걸지도 몰라.","JPN":"もしかしたら、一人で決着をつけたほうがいいのかもしれない。","ENG":"Maybe it’s for the best that I finish this all by myself.","TWN":"也許一個人結束這一切比較好。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"으윽……","JPN":"ううっ……","ENG":"Urgh...","TWN":"咳咳……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"서둘러야…… 해.","JPN":"急が……ないと…‥","ENG":"I have to hurry...","TWN":"要加快……動作。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_SILHOUETTE","text":{"KOREA":"결국 여기까지 이르셨군요, 당주님.","JPN":"結局ここまでいらしたのですね、ご当主。","ENG":"So, Lady Nanahara. You’re here, finally.","TWN":"堂主，您終於到這裡了。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"장로…… 당신이 어떻게 여길 온 거죠?","JPN":"長老……貴方がなぜここにいるのですか？","ENG":"Elder... How did you get here?","TWN":"長老……怎麼會來這裡？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"이 땅은…… 평범한 사람이 들어와도 괜찮은 곳이 아닙니다. 어서 떠나세요.","JPN":"この土地は……普通の人が入ってはならない危険な場所です。\\nすぐに戻ってください。","ENG":"This land is dangerous for ordinary people. You must leave.","TWN":"這個地方……不是一般人可以隨意進來的，請快離開。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"당주께선, 봉인 전승을 실제로 보신 적이 있으신지요?","JPN":"ご当主は、封印の伝承を実際にご覧になったことがありますか？","ENG":"Have you actually witnessed the sealing ritual?","TWN":"堂主，您見過傳承封印吧？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……네?","JPN":"……はい？","ENG":"… Pardon?","TWN":"……嗯？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"과거, 인간의 선조들은 영생을 얻기 위해 오로치가 택한 무녀를 죽였습니다.","JPN":"過去、人間の祖先は永遠の命を得るために、\\nオロチが選んだ巫女を殺しました。","ENG":"In the old days, humans killed Orochi’s priestesses, in order to have eternal life for themselves.","TWN":"以前，人類的祖先爲了獲得永生，而殺死大蛇揀選的巫女。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"분노한 오로치는 영생을 탐한 인간들의 명줄을 오히려 빼앗는 저주를 내렸지요.","JPN":"激怒したオロチは永遠の命を貪った人間に対して、\\n逆に命を奪う呪いをかけました。","ENG":"Orochi was furious, and she cursed those humans to die.","TWN":"憤怒的大蛇咒詛那些人，要奪走他們的命脈。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"그리고, 그 분노를 잠재운 것은 다름아닌 무녀의 후손들.","JPN":"そして、その怒りを鎮めたのは他ならぬ巫女の子孫たち。","ENG":"And it was none other than the descendants of the priestess who quelled that fury.","TWN":"而平息大蛇憤怒的不是別人，正是巫女的後裔。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"오로치가 더없이 아끼고 사랑했던 자의 핏줄이지요.","JPN":"オロチが心から大切にし、愛した者の血筋です。","ENG":"They were from the bloodline of the woman whom Orochi cared deeply for.","TWN":"是大蛇疼愛之人的血脈。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"당주께선 정녕 이 전승을 사실이라고 믿으시나요?","JPN":"ご当主は本当にこの伝承が真実だと信じていますか？","ENG":"Do you believe this legend to be true?","TWN":"堂主相信個傳承是真的嗎？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"고작 당주의 피를 바친다고 해서, 오로치가 영영 그 안에 갇혀 있을 거라고 생각하시나요?","JPN":"当主の血を捧げた程度で、\\nオロチを永遠に封じることができると思っているのですか？","ENG":"Do you really think Orochi will stay within the seal forever just because a priestess is sacrificed?","TWN":"只要獻上堂主的鮮血，大蛇就會永遠會被困在那裡面嗎？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"제가 이 선택을 하는 것은…… 다른 미래를 보지 못했기 때문입니다.","JPN":"私がこの選択をしたのは……他の未来が見えなかったからです。","ENG":"I chose this path... because I failed to see any other possibilities.","TWN":"我會做這個選擇…是因爲沒看到其他的未來。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"이렇게라도 하지 않으면…… 아무것도 변하지 않습니다.","JPN":"こうでもしなければ……何も変わりません。","ENG":"If I don’t do this... nothing will change.","TWN":"不這麼做的話……什麼都不會改變。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"전…… 연합을 위해…… 모두를 위해 시간을 벌고자 할 뿐이에요.","JPN":"私は……連合のために……\\nみなさんのために時間を稼ぎたいだけです。","ENG":"All I want is to buy the Alliance more time...","TWN":"我…只是在爲聯盟…爲大家，爭取時間而已。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"제 뒤는 치후유가 맡아줄 거예요.","JPN":"この後は千冬に託します。","ENG":"Chifuyu will take care of the rest.","TWN":"千冬會接續我的責任。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"거짓말이 느셨군요.","JPN":"嘘が上手になりましたね。","ENG":"You’ve become a pretty good liar.","TWN":"說謊都不打草稿呢？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"당주님은 단지, 3년 전부터 시작된 죄책감으로부터 도망치고 싶은 것이 아닌가요?","JPN":"ご当主はただ、3年前の事件の罪悪感から\\n逃げ出したいだけなのではありませんか？","ENG":"All you want is to run away from your guilt over what happened three years ago.","TWN":"堂主只是想從3年前的罪惡感中得到解脫而已吧？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"마지막 책임을 다하는 것이 그런 의미라면……","JPN":"最後の責任を果たすということが、そのような意味なら……","ENG":"If that’s the only way to fulfill my responsibilities...","TWN":"如果這是你對於盡到最後的責任的解讀……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"사람들에게 그렇게 기억된다고 하더라도, 상관없습니다.","JPN":"人々にそのように記憶されたとしても、構いません。","ENG":"I don’t mind people considering my actions from such perspectives.","TWN":"若大家會對我留下那樣的印象也無所謂。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"모두를 등지고 죽음으로부터 도망치는 것보단 나으니까요.","JPN":"みなさんに背を向けて死から逃げるよりはましですから。","ENG":"It’s much better than running away from my death, and my responsibilities.","TWN":"總比拋下所有人脫離死亡來得好。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"……그런가요.","JPN":"……そうですか。","ENG":"I see.","TWN":"……是嗎？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"<color=#ffd34c>그분</color>의 말씀이 맞을지도 모르겠군요.","JPN":"<color=#ffd34c>あの方</color>のおっしゃるとおりかもしれませんね。","ENG":"Maybe <color=#ffd34c>she</color> is right.","TWN":"或許<color=#ffd34c>那位</color>說的是對的。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"어린 것들은 정말이지, 순수하네요.","JPN":"子どもたちは、実に純粋な存在です。","ENG":"You youngsters are so naive.","TWN":"小孩子真的很單純。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그분…… 이라고요?","JPN":"あの方……とは？","ENG":"She?","TWN":"那位……是？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"크읏?!","JPN":"くうっ！？","ENG":"Huh?!","TWN":"唔？！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"장로, 이게 대체 무슨 짓이죠?","JPN":"長老、これはいったいどういうことですか？","ENG":"Elder, what are you doing?","TWN":"長老，你這是在做什麼？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L6_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"카운터들은 세대를 거듭할수록 약해진다고 알았는데……","JPN":"カウンターは世代を重ねるごとに弱くなると聞いていたが……","ENG":"I heard Counters grow weaker as generations pass by...","TWN":"我以爲制裁者會隨著年齡的增長而變弱……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L7_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"네 동생과 다르게 넌 쓸데없이 너무 비범하단 말이지.","JPN":"貴様は妹と違い、無駄に非凡すぎるのだ。","ENG":"But you’re way too strong, unlike your sister.","TWN":"你和你妹妹不同，你太不平凡了。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"으윽!","JPN":"ううっ！","ENG":"Argh!","TWN":"唔！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"네가 오로치 추방 계획에 대해 말했을 땐, 나도 놀랐다.","JPN":"貴様がオロチ追放計画について語ったときは私も驚いた。","ENG":"When you told us about your plan to purge Orochi, I was very surprised.","TWN":"你提到驅逐大蛇的計劃時，我也很驚訝。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"선대 당주도 꿈꾸지 못했던 방법을 그 후손이 알아낼 줄이야.","JPN":"先代当主も思いつかなかった方法がその子孫から出るとは。","ENG":"You figured out something that your predecessors could not even dream of.","TWN":"沒想到連先祖堂主也想不到的方法，她的後裔竟然會知道。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"내가 손을 쓰지 않았더라면 정말 성공했을지도 모르지.","JPN":"私が先に手を打たなかったら、本当に成功していたかもしれぬ。","ENG":"It might have worked, if I didn’t do something about it.","TWN":"要不是我出手，說不定真的會成功。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……뭐라고요?","JPN":"……なんですって？","ENG":"What?","TWN":"……什麼？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그럼 당신이…… 어떻게 그런 짓을?","JPN":"それでは貴方が……？　どうしてそんなことを……？","ENG":"Then you... How could you?","TWN":"你……為什麼要那麼做？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"대체 언제부터 연합을 배신하고 있었던 거죠?!","JPN":"いったいいつから連合を裏切っていたのですか！？","ENG":"How long has this betrayal been going?","TWN":"你是從什麼時候開始背叛聯盟的？！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"배신?","JPN":"裏切り？","ENG":"Betrayal?","TWN":"背叛？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"후후, 너처럼 새파란 것이 뭘 알겠니?","JPN":"フフ、貴様のような青二才に何がわかる。","ENG":"Hah hah, you’re too young to understand.","TWN":"呵呵，你這種小鬼懂什麼？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"애초에 날 일원으로 받아들이지 않았던 건 너희 가문이었어.","JPN":"そもそも、私を一族の一員として受け入れなかったのは貴様の家門だった。","ENG":"It was your family that didn’t want me in the first place.","TWN":"當初是你的家族不將我視為成員。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"같은 가문에서 태어났지만, 무녀의 신력이 없다는 이유로 당주가 되지 못했어.","JPN":"同じ家に生まれたのに、巫女の神力がないという理由で\\n当主になれなかった。","ENG":"I have the same name as you, yet you shunned me for not having enough power to become the priestess.","TWN":"雖然出生在同一個家族，只因爲沒有巫女的神力，就無法當上堂主。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"너희 당주들이 연합의 권력을 휘두를 때, 난 아무 권리도 누리지 못한 채 없는 사람 취급을 받아야 했지.","JPN":"貴様ら当主どもが連合の権力を振るう時、\\n私は何の権利も有さず、まるでそこに存在しないかのような人間の扱いを受けなければならなかった。","ENG":"While you were enjoying your power and status, I was nothing.","TWN":"當你們堂主們在行使聯盟的權利時，我卻活該無法享有任何權利。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"하지만.","JPN":"だが。","ENG":"But...","TWN":"不過。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"오로치님을 배반하고 선조를 죽인 인간들의 편에 선 너희 가짜들과 나는… 핏줄부터가 달랐다.","JPN":"オロチ様を裏切って先祖を殺した人間側に付いた、貴様ら偽物と私は……血筋から違っていたのだ。","ENG":"I am not of the same blood as you fakes, who sided with the people who betrayed Orochi and killed your ancestor.","TWN":"你們站在背叛大蛇又殺害先祖的人那邊……我的血統跟你們可不同。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"그래서 난 오로치님에게 인정받을 수 있었던 거다.","JPN":"だから私は、オロチ様に認められたのだ。","ENG":"That’s why Orochi chose me.","TWN":"所以我才能得到大蛇的認同。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"장로……? 그 모습은 대체?","JPN":"長老……？　その姿はいったい！？","ENG":"Elder? Your face...","TWN":"長老……？你的樣子怎麼會？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"선대 당주께서 태어날 때부터 연합의 중역을 맡고 있던 분이…","JPN":"先代当主が生まれた時から連合の重役を務めていた方が……","ENG":"You were already an elder when the previous family leader was born...","TWN":"你不是從先祖堂主出生時，就在聯盟中擔負重任…"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"어떻게 그런 모습을 하고 있을 수 있는 거죠?","JPN":"なぜそのような姿のままでいられるのですか？","ENG":"How can you be still so young?","TWN":"怎麼可能維持那般的容貌？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"무녀의 피를 타고나지 않은 덕분에 난 그분의 속삭임을 들을 수 있었어.","JPN":"巫女の血に恵まれなかったおかげで、\\n私はあの方のささやきを聞くことができた。","ENG":"Because I didn’t have the blood of the priestess, I could hear her whispers.","TWN":"幸好我身上沒有流著巫女的血，我才能聽到她的耳語。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"그리고 새로운 희망을 얻었지.","JPN":"そして新たな希望を得た。","ENG":"And I could hope again.","TWN":"並且獲得新的希望。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"너희들의 그 잘난 무녀의 핏줄조차 얻지 못했던 영생을, 그분께서는 나에게 주셨거든.","JPN":"貴様らのそのうぬぼれた巫女の血筋ですら得られなかった永遠の命を、\\nあの方は私に与えてくださったのだ。","ENG":"Lord Orochi gave me the eternal life that even you, the priestesses, couldn’t have.","TWN":"你們那引以為傲的巫女血脈，都得不到的永生，她卻賜給我。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"오로치님의 명을 받고, 그분을 직접 모시기만을 기다려왔어.","JPN":"オロチ様の命を受けて、あの方を直接お迎えすることだけを待っていた。","ENG":"I followed her will, and I waited for the day I could actually meet and serve her.","TWN":"接到大蛇的命令後，我一直等待親自接見她。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"난 오로치님의 이상대로, 더럽혀진 인간들을 더 이상 이 땅에 남기지 않을 것이다.","JPN":"私はオロチ様の理想どおり、\\n穢れた人間どもをこの地から根絶やしにするつもりだ。","ENG":"I will remove every corrupted human from the face of the earth, as Lord Orochi wishes.","TWN":"我要實踐大蛇的理想，將那些受到污染的人，一個也不留地從這塊土地上除去。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그렇게 말하는 당신도…… 오랜 세월 속에서 지독하게 더럽혀진 것 같군요.","JPN":"そういう貴方も……長い歳月を経て、酷く穢れてしまったようですね。","ENG":"You lived so long... and you’ve fallen into the abyss.","TWN":"說出這些話的你……似乎也在這漫長的歲月裡，被污染得很嚴重。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"후훗, 그 입방정이 자기 명을 재촉하는 줄도 모르는구나.","JPN":"フフッ、その口の利き方が貴様の死を早めることになるのもわからぬか。","ENG":"Hah hah, your tongue will drag you to hell.","TWN":"呵呵，你那張嘴會害你短命呢。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"이제, 여기서 그만 잠들어라.","JPN":"そろそろ、ここで睡るがいい。","ENG":"Now be silent forever.","TWN":"你就在這裡沈睡吧。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"거기서 더 움직이면.","JPN":"そこから少しでも動いたら。","ENG":"If you make a move...","TWN":"你要是敢再動，"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"이번엔 머리를 쏘겠습니다.","JPN":"今度は頭を射抜きます。","ENG":"I will shoot you in the head this time.","TWN":"這次射的就是你的頭。"},"stage":{"bg":"NANAHARA_01","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L50_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"……나유카 가문.","JPN":"……奈由香家。","ENG":"The Nayukas.","TWN":"……南裕夏家族。"},"stage":{"bg":"NANAHARA_01","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"가족의 죽음이 두려워서 연합을 버린 집안이, 이제 와서 가문의 의무를 다시 짊어지다니.","JPN":"家族の死を恐れて連合を捨てた家門が、\\n今更家門の義務を再び負おうとするとは。","ENG":"Your grandfather abandoned the Alliance in fear of losing his family, but now you’re back here to fulfill your duty.","TWN":"害怕家人死亡而拋棄聯盟的家族，如今又承擔起家族的義務嗎？"},"stage":{"bg":"NANAHARA_01","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"고작 며칠 사이에 대의를 위해 싸우겠다는 신념이라도 생긴 것이냐?","JPN":"このわずか数日の間に大義のために戦う信念でも生まれたのか？","ENG":"Did you get faith in justice during the past few days?","TWN":"短短幾天內，就產生要為正義而戰的信念嗎？"},"stage":{"bg":"NANAHARA_01","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"할아버지는 한 번도 내게 연합에 대해 말해준 적이 없어요.","JPN":"祖父は僕に一度も連合について話してくれたことがありません。","ENG":"Grandpa never told me about the Alliance.","TWN":"爺爺從來沒跟我說過關於聯盟的事。"},"stage":{"bg":"NANAHARA_01","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"우리 집안이 그런 곳에서 싸웠다는 사실도 전 모릅니다.","JPN":"僕の家が連合所属として戦っていたという事実さえ、僕は知りませんでした。","ENG":"I didn’t even know my family was in this war.","TWN":"我連我們家族在那種地方戰鬥過的事都不知道。"},"stage":{"bg":"NANAHARA_01","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그리고, 지금도 그건 아무래도 좋다고 생각하고 있죠.","JPN":"そして今も、そんなことはどうでもいいと思ってます。","ENG":"And, to be honest, that’s none of my concern even now.","TWN":"而且，現在也毫不在意。"},"stage":{"bg":"NANAHARA_01","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"뭐라고?","JPN":"なんだと？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"NANAHARA_01","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"대의나 희생 같은 어려운 말은 몰라.","JPN":"大義や犠牲みたいな難しい言葉はわからない。","ENG":"I don’t care about great causes or sacrifice.","TWN":"我不懂正義或犧牲這種艱澀的詞彙。"},"stage":{"bg":"NANAHARA_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"난 가문의 의무를 짊어질 마음도 없고, 연합을 위해서 목숨을 걸고 싶은 생각도 없어.","JPN":"僕は家門の義務を負うつもりもないし、連合のために命をかけるつもりもない。","ENG":"I’m not here to fulfill my family’s duty, nor do I want to die for the Alliance.","TWN":"我不想承擔家族的義務，也不想爲聯盟賣命。"},"stage":{"bg":"NANAHARA_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"난 그저, 내 일상을 지키려는 것뿐이야.","JPN":"僕はただ、僕の日常を守りたいだけだ。","ENG":"All I want is to protect my everyday life.","TWN":"我只想守護我的日常生活。"},"stage":{"bg":"NANAHARA_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그걸 위해서라면, 뭐든지 하겠어!","JPN":"そのためなら、何だってやる！","ENG":"I will do anything to do that!","TWN":"爲了能夠平凡過日子，我什麼都願意做！"},"stage":{"bg":"NANAHARA_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"후후훗.","JPN":"フフフフ。","ENG":"Hah hah hah.","TWN":"呵呵呵。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"우습구나. 그런 대수롭지 않은 각오로 여기까지 오다니.","JPN":"面白い。そんなくだらぬ覚悟でここまで来るとは。","ENG":"Such shallowness. It’s pathetic.","TWN":"真可笑，竟然用那種兒戲的心態來到這裡。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"신념을 부르짖던 자들도 반나절만 고문하면 자신만을 위해 울부짖거늘.","JPN":"信念を掲げる者も、たった半日程度の拷問で\\n自分だけのために命乞いをするものだ。","ENG":"Even those with the strongest determination break down after a day of torture.","TWN":"那些說自己有信念的人，只要拷問個半天，就會忘得一乾二凈。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"……과연 너 같은 녀석이 본색을 드러내면 당주가 어떤 표정을 짓게 될지, 기대되는구나.","JPN":"……貴様のような奴が本性を現わした時、当主がどのような表情を見せるか楽しみだな。","ENG":"I can’t wait to see the look on Lady Nanahara’s face when you reveal your true colors.","TWN":"……真令人期待，像你種傢伙露出真面目時，堂主會有什麼樣的表情。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"이건…… 침식체?","JPN":"これは……侵食体？","ENG":"You summoned... C.O.s?","TWN":"這是…… 侵蝕體？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"놀랐느냐? 이 또한 오로치께서 내게 하신 권능이란다.","JPN":"驚いたか？　これもまたオロチ様が私に与えてくださった権能だ。","ENG":"Are you surprised? This is one of the powers that Lord Orochi granted me.","TWN":"嚇到了嗎？這也是大蛇賜給我的能力。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"귀찮은 것들을 의심받지 않고 제거하는데 요긴하게 써왔지.","JPN":"面倒事を疑われることなく排除するのに重宝したぞ。","ENG":"It’s been very useful when getting rid of troublemakers.","TWN":"我一直很小心使用，才不會在除掉麻煩的傢伙時受到懷疑。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"자! 저것들을 갈기갈기 찢어 죽여라!","JPN":"さあ！　あいつらを八つ裂きにしろ！","ENG":"Go! Rip them apart!","TWN":"去吧！把他們撕爛！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};